import React, { useState, useEffect, useRef, useCallback } from 'react';
import { Calendar, CheckCircle, DollarSign, Menu, X, ArrowRight, Star, Phone, Mail, Clock } from 'lucide-react';

// Main App Component
// API Configuration
const API_URL = 'https://gpc-backend-production.up.railway.app/api';

// API Helper Functions
const api = {
  // Auth endpoints
  register: async (userData) => {
    const response = await fetch(`${API_URL}/auth/register`, {
      method: 'POST',
      headers: { 'Content-Type': 'application/json' },
      body: JSON.stringify(userData)
    });
    return response.json();
  },
  
  login: async (email, password) => {
    const response = await fetch(`${API_URL}/auth/login`, {
      method: 'POST',
      headers: { 'Content-Type': 'application/json' },
      body: JSON.stringify({ email, password })
    });
    return response.json();
  },
  
  // Quote endpoints
  submitQuote: async (quoteData, token) => {
    const response = await fetch(`${API_URL}/quotes/request`, {
      method: 'POST',
      headers: { 
        'Content-Type': 'application/json',
        'Authorization': token ? `Bearer ${token}` : ''
      },
      body: JSON.stringify(quoteData)
    });
    return response.json();
  },
  
  getMyQuotes: async (token) => {
    const response = await fetch(`${API_URL}/quotes/my-requests`, {
      headers: { 'Authorization': `Bearer ${token}` }
    });
    return response.json();
  },
  
  // Project endpoints
  getMyProjects: async (token) => {
    const response = await fetch(`${API_URL}/projects/my-projects`, {
      headers: { 'Authorization': `Bearer ${token}` }
    });
    return response.json();
  },
  
  getProjectDetails: async (projectId, token) => {
    const response = await fetch(`${API_URL}/projects/${projectId}`, {
      headers: { 'Authorization': `Bearer ${token}` }
    });
    return response.json();
  },
  
  // Message endpoints
  getMessages: async (token) => {
    const response = await fetch(`${API_URL}/messages`, {
      headers: { 'Authorization': `Bearer ${token}` }
    });
    return response.json();
  },
  
  sendMessage: async (messageData, token) => {
    const response = await fetch(`${API_URL}/messages`, {
      method: 'POST',
      headers: { 
        'Content-Type': 'application/json',
        'Authorization': `Bearer ${token}` 
      },
      body: JSON.stringify(messageData)
    });
    return response.json();
  }
};
export default function HomeCareWebsite() {
  const [currentPage, setCurrentPage] = useState('home');
  const [mobileMenuOpen, setMobileMenuOpen] = useState(false);

  // Authentication state
  const [user, setUser] = useState(null);
  const [token, setToken] = useState(null);
  const [isAuthenticated, setIsAuthenticated] = useState(false);

  // Check for existing auth on page load
  useEffect(() => {
    const savedToken = localStorage.getItem('authToken');
    const savedUser = localStorage.getItem('user');
    
    if (savedToken && savedUser) {
      setToken(savedToken);
      setUser(JSON.parse(savedUser));
      setIsAuthenticated(true);
    }
  }, []);

  // Auth helper functions
  const handleLogin = (userData, authToken) => {
    setUser(userData);
    setToken(authToken);
    setIsAuthenticated(true);
    localStorage.setItem('authToken', authToken);
    localStorage.setItem('user', JSON.stringify(userData));
  };

  const handleLogout = () => {
    setUser(null);
    setToken(null);
    setIsAuthenticated(false);
    localStorage.removeItem('authToken');
    localStorage.removeItem('user');
    setCurrentPage('home');
  };
  

  const renderPage = () => {
    switch(currentPage) {
      case 'home':
        return <HomePage setCurrentPage={setCurrentPage} />;
      case 'services':
        return <ServicesPage setCurrentPage={setCurrentPage} />;
      case 'request-quote':
        return <RequestQuotePage user={user} token={token} isAuthenticated={isAuthenticated} />;
      case 'portal':
  if (!isAuthenticated) {
    return <LoginPage onLoginSuccess={handleLogin} setCurrentPage={setCurrentPage} />;
  }
  return user?.user_type === 'admin' 
    ? <AdminDashboard user={user} token={token} onLogout={handleLogout} />
    : <CustomerPortal user={user} token={token} onLogout={handleLogout} />;
      case 'register':
        return <RegisterPage onRegisterSuccess={handleLogin} setCurrentPage={setCurrentPage} />;
      case 'forgot-password':
        return <ForgotPasswordPage setCurrentPage={setCurrentPage} />;
      case 'about':
        return <AboutPage />;
      default:
        return <HomePage setCurrentPage={setCurrentPage} />;
    }
  };

  return (
    <div style={{ 
      fontFamily: '"Barlow", "Instrument Sans", -apple-system, sans-serif',
      minHeight: '100vh',
      background: '#0a0a0a',
      color: '#f5f5f5',
      position: 'relative',
      overflow: 'hidden'
    }}>
      {/* Animated background elements */}
      <div style={{
        position: 'fixed',
        top: '-50%',
        left: '-50%',
        width: '200%',
        height: '200%',
        background: 'radial-gradient(circle at 30% 50%, rgba(220, 38, 38, 0.08) 0%, transparent 50%), radial-gradient(circle at 70% 70%, rgba(255, 255, 255, 0.05) 0%, transparent 50%)',
        animation: 'drift 30s ease-in-out infinite',
        pointerEvents: 'none',
        zIndex: 0
      }} />
      
      <style>{`
        @import url('https://fonts.googleapis.com/css2?family=Barlow:wght@400;500;600;700;800&family=Oswald:wght@400;500;600;700&display=swap');
        
        @keyframes drift {
          0%, 100% { transform: translate(0, 0) rotate(0deg); }
          50% { transform: translate(-5%, 5%) rotate(2deg); }
        }
        
        @keyframes fadeInUp {
          from {
            opacity: 0;
            transform: translateY(30px);
          }
          to {
            opacity: 1;
            transform: translateY(0);
          }
        }
        
        @keyframes slideInLeft {
          from {
            opacity: 0;
            transform: translateX(-40px);
          }
          to {
            opacity: 1;
            transform: translateX(0);
          }
        }
        
        @keyframes scaleIn {
          from {
            opacity: 0;
            transform: scale(0.9);
          }
          to {
            opacity: 1;
            transform: scale(1);
          }
        }
        
        .animate-in {
          animation: fadeInUp 0.8s ease-out forwards;
        }
        
        .animate-slide {
          animation: slideInLeft 0.7s ease-out forwards;
        }
        
        .animate-scale {
          animation: scaleIn 0.6s ease-out forwards;
        }
        
        * {
          margin: 0;
          padding: 0;
          box-sizing: border-box;
        }
      `}</style>

      {/* Navigation */}
      <Navigation 
        currentPage={currentPage} 
        setCurrentPage={setCurrentPage}
        mobileMenuOpen={mobileMenuOpen}
        setMobileMenuOpen={setMobileMenuOpen}
      />

      {/* Main Content */}
      <div style={{ position: 'relative', zIndex: 1 }}>
        {renderPage()}
      </div>

      {/* Footer */}
      <Footer setCurrentPage={setCurrentPage} />
    </div>
  );
}

// Navigation Component
function Navigation({ currentPage, setCurrentPage, mobileMenuOpen, setMobileMenuOpen }) {
  return (
    <nav style={{
      position: 'sticky',
      top: 0,
      zIndex: 100,
      background: '#ffffff',
      borderBottom: '3px solid #dc2626',
      boxShadow: '0 4px 16px rgba(0,0,0,0.12)'
    }}>
      <div style={{
        maxWidth: '1400px',
        margin: '0 auto',
        padding: '0 2rem',
        height: '100px',
        display: 'grid',
        gridTemplateColumns: '220px 1fr auto',
        alignItems: 'center',
        gap: '1rem'
      }}>
        <div
          onClick={() => setCurrentPage('home')}
          style={{ cursor: 'pointer', display: 'flex', alignItems: 'center' }}
        >
          <img
            src="data:image/png;base64,"
            alt="Greenwich Property Care"
            style={{ height: '90px', width: 'auto', display: 'block' }}
          />
        </div>

        {/* Desktop Menu */}
        <div style={{ display: 'flex', gap: '2.5rem', alignItems: 'center' }}>
          <div style={{ display: 'flex', gap: '2.5rem', '@media (max-width: 768px)': { display: 'none' } }}>
            {['home', 'services', 'request-quote', 'about', 'portal'].map(page => (
              <button
                key={page}
                onClick={() => setCurrentPage(page)}
                style={{
                  background: 'none',
                  border: 'none',
                  color: currentPage === page ? '#dc2626' : '#333333',
                  cursor: 'pointer',
                  fontSize: '0.95rem',
                  fontWeight: '500',
                  transition: 'all 0.3s ease',
                  textTransform: 'capitalize',
                  position: 'relative',
                  padding: '0.5rem 0',
                  letterSpacing: '0.01em'
                }}
                onMouseEnter={(e) => e.target.style.color = '#dc2626'}
                onMouseLeave={(e) => e.target.style.color = currentPage === page ? '#dc2626' : '#333333'}
              >
                {page === 'request-quote' ? 'Get Quote' : page}
                {currentPage === page && (
                  <div style={{
                    position: 'absolute',
                    bottom: '-2px',
                    left: 0,
                    right: 0,
                    height: '2px',
                    background: 'linear-gradient(90deg, #dc2626, #ef4444)',
                    borderRadius: '2px'
                  }} />
                )}
              </button>
            ))}
          </div>
          
          {/* Mobile Menu Button */}
          <button
            onClick={() => setMobileMenuOpen(!mobileMenuOpen)}
            style={{
              background: 'none',
              border: 'none',
              color: '#dc2626',
              cursor: 'pointer',
              display: 'none',
              '@media (max-width: 768px)': { display: 'block' }
            }}
          >
            {mobileMenuOpen ? <X size={24} /> : <Menu size={24} />}
          </button>
        </div>
      </div>

      {/* Mobile Menu Dropdown */}
      {mobileMenuOpen && (
        <div style={{
          background: '#ffffff',
          borderTop: '1px solid rgba(220, 38, 38, 0.2)',
          padding: '1.5rem 2rem'
        }}>
          {['home', 'services', 'request-quote', 'about', 'portal'].map(page => (
            <button
              key={page}
              onClick={() => {
                setCurrentPage(page);
                setMobileMenuOpen(false);
              }}
              style={{
                background: 'none',
                border: 'none',
                color: currentPage === page ? '#dc2626' : '#333333',
                cursor: 'pointer',
                fontSize: '1rem',
                fontWeight: '500',
                display: 'block',
                width: '100%',
                textAlign: 'left',
                padding: '0.75rem 0',
                textTransform: 'capitalize',
                borderBottom: '1px solid rgba(255, 255, 255, 0.05)'
              }}
            >
              {page === 'request-quote' ? 'Get Quote' : page}
            </button>
          ))}
        </div>
      )}
    </nav>
  );
}

